	select
		'SB' || lpad(CAST(coalesce(max(CAST(substring(stdr_bsns_cd, 3) AS INTEGER)), 0) + 1 AS VARCHAR), 8, '0')
	from uspt_stdr_bsns

/** UsptStdrBsnsDao.insert */
insert into uspt_stdr_bsns
					(
						stdr_bsns_cd
						, bsns_cl_id
						, stdr_bsns_nm
						, begin_year
						, tot_bsns_pd
						, bsns_type_cd
						, cnsrtm
						, chrg_dept_nm
						, bsns_sumry
						, ecshg_instt_nm
						, ecshg_instt_cd
						, erp_cd
						, task_type_cd
						, enabled
						, creator_id
						, created_dt
						, updater_id
						, updated_dt
					)
			values	(
						#{stdrBsnsCd}
						, #{bsnsClId}
						, #{stdrBsnsNm}
						, #{beginYear}
						, #{totBsnsPd}
						, #{bsnsTypeCd}
						, #{cnsrtm}
						, #{chrgDeptNm}
						, #{bsnsSumry}
						, #{ecshgInsttNm}
						, #{ecshgInsttCd}
						, #{erpCd}
						, #{taskTypeCd}
						, true
						, #{creatorId}
						, #{createdDt}
						, #{updaterId}
						, #{updatedDt}
					)

mapper.update:
/** UsptStdrBsnsDao.update */
update uspt_stdr_bsns
set
	updater_id			= #{updaterId}
	, updated_dt		= #{updatedDt}
	, bsns_cl_id		= #{bsnsClId}
	, stdr_bsns_nm		= #{stdrBsnsNm}
	, begin_year		= #{beginYear}
	, tot_bsns_pd		= #{totBsnsPd}
	, bsns_type_cd		= #{bsnsTypeCd}
	, cnsrtm			= #{cnsrtm}
	, chrg_dept_nm		= #{chrgDeptNm}
	, bsns_sumry		= #{bsnsSumry}
	, ecshg_instt_nm	= #{ecshgInsttNm}
	, ecshg_instt_cd	= #{ecshgInsttCd}
	, erp_cd			= #{erpCd}
where
	stdr_bsns_cd = #{stdrBsnsCd}

/** UsptStdrBsnsDao.updateTaskType */
update uspt_stdr_bsns
set
	updater_id		= #{updaterId}
	, updated_dt	= #{updatedDt}
	, task_type_cd	= #{taskTypeCd}
where
	stdr_bsns_cd = #{stdrBsnsCd}

/** UsptStdrBsnsDao.updateUnable */
update uspt_stdr_bsns
set
	updater_id		= #{updaterId}
	, updated_dt	= #{updatedDt}
	, enabled		= false
where
	stdr_bsns_cd = #{stdrBsnsCd}
